    if (inst_.neg_hi & 2) {
      b_hi = -b_hi;
    }
    if (inst_.neg_hi & 4) {
      c_hi = -c_hi;
    }
    float rlo = std::fma(a_lo, b_lo, c_lo);
    float rhi = std::fma(a_hi, b_hi, c_hi);
    vdst.write_lane(wf, lane,
                    util::f32_to_f16(rlo) | (static_cast<uint32_t>(util::f32_to_f16(rhi)) << 16));
