      a = std::fabs(a);
    if (inst_.neg_hi & 2)
      b = std::fabs(b);
    if (inst_.neg_hi & 4)
      c = std::fabs(c);
    if (inst_.neg & 1)
      a = -a;
    if (inst_.neg & 2)
      b = -b;
    if (inst_.neg & 4)
      c = -c;
