    src0.set_delegate(dpp_src0_.get());
  if (dpp_src1_)
    src1.set_delegate(dpp_src1_.get());
  auto &cu = wf.cu();
  uint32_t vb = wf.vgpr_alloc().base;
  uint32_t dst = vb + *Isa::resolved_vgpr_offset(wf, vdst.opr_type_, vdst.encoding_value_,
                                                 vdst.vgpr_msb_role());
